import { useState, useEffect } from "react";

const POSTER_IMG = "data:image/jpeg;base64,";

const TYPO_IMG = "data:image/png;base64,";

const SPACE_BG = "data:image/svg+xml;base64,";

const TICKETS = [
  "NOVA", "BOLT", "HAZE", "REEF",
  "GLOW", "DUSK", "ROSE", "MIST",
  "JADE", "WOLF", "SAGE", "TEAL",
  "ONYX", "LIME", "AQUA", "MARS",
  "PINE", "RUBY", "ECHO", "GOLD"
];

const ADMIN_PASSWORD = "morock2026";
const KAKAO_LINK = "https://qr.kakaopay.com/PLACEHOLDER";
const SPACE_LAYERS = [
  "radial-gradient(circle at 52% 14%, rgba(74,19,91,.62) 0, rgba(31,7,48,.34) 25%, transparent 55%)",
  "radial-gradient(circle at 22% 28%, rgba(255,66,183,.16) 0, rgba(255,66,183,.06) 18%, transparent 42%)",
  "radial-gradient(circle at 78% 22%, rgba(55,162,255,.15) 0, rgba(55,162,255,.05) 20%, transparent 46%)",
  "radial-gradient(circle at 65% 72%, rgba(255,66,183,.09) 0, transparent 35%)",
  "radial-gradient(circle at 18% 82%, rgba(55,162,255,.08) 0, transparent 38%)",
  "radial-gradient(circle at 8% 6%, rgba(255,255,255,.68) 0 .32px, transparent .56px)",
  "radial-gradient(circle at 17% 13%, rgba(255,66,183,.52) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 29% 8%, rgba(79,205,255,.48) 0 .3px, transparent .55px)",
  "radial-gradient(circle at 44% 17%, rgba(255,255,255,.55) 0 .32px, transparent .58px)",
  "radial-gradient(circle at 61% 7%, rgba(255,66,183,.44) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 83% 12%, rgba(255,255,255,.58) 0 .3px, transparent .56px)",
  "radial-gradient(circle at 93% 21%, rgba(79,205,255,.45) 0 .3px, transparent .55px)",
  "radial-gradient(circle at 11% 24%, rgba(79,205,255,.42) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 25% 31%, rgba(255,255,255,.5) 0 .3px, transparent .54px)",
  "radial-gradient(circle at 38% 26%, rgba(255,66,183,.46) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 53% 35%, rgba(255,255,255,.48) 0 .3px, transparent .56px)",
  "radial-gradient(circle at 70% 30%, rgba(79,205,255,.38) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 88% 37%, rgba(255,66,183,.45) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 5% 43%, rgba(255,255,255,.44) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 19% 52%, rgba(255,66,183,.42) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 34% 47%, rgba(79,205,255,.42) 0 .27px, transparent .52px)",
  "radial-gradient(circle at 49% 55%, rgba(255,255,255,.52) 0 .3px, transparent .55px)",
  "radial-gradient(circle at 64% 49%, rgba(255,66,183,.38) 0 .25px, transparent .5px)",
  "radial-gradient(circle at 78% 58%, rgba(255,255,255,.46) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 94% 51%, rgba(79,205,255,.4) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 12% 66%, rgba(255,255,255,.5) 0 .29px, transparent .54px)",
  "radial-gradient(circle at 27% 72%, rgba(79,205,255,.38) 0 .25px, transparent .5px)",
  "radial-gradient(circle at 43% 68%, rgba(255,66,183,.42) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 57% 78%, rgba(255,255,255,.48) 0 .3px, transparent .55px)",
  "radial-gradient(circle at 73% 70%, rgba(79,205,255,.4) 0 .27px, transparent .52px)",
  "radial-gradient(circle at 89% 82%, rgba(255,66,183,.4) 0 .26px, transparent .5px)",
  "radial-gradient(circle at 7% 91%, rgba(79,205,255,.36) 0 .24px, transparent .48px)",
  "radial-gradient(circle at 23% 86%, rgba(255,255,255,.46) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 39% 94%, rgba(255,66,183,.38) 0 .25px, transparent .5px)",
  "radial-gradient(circle at 69% 91%, rgba(255,255,255,.44) 0 .28px, transparent .52px)",
  "radial-gradient(circle at 96% 94%, rgba(79,205,255,.36) 0 .24px, transparent .48px)",
  "linear-gradient(180deg, #060313 0%, #050210 38%, #03020b 100%)",
].join(",");

export default function App() {
  const [view, setView] = useState("main"); // main | ticket | payment | admin
  const [ticketInput, setTicketInput] = useState("");
  const [ticketStatus, setTicketStatus] = useState(null); // null | "valid" | "used" | "invalid"
  const [adminPass, setAdminPass] = useState("");
  const [adminAuth, setAdminAuth] = useState(false);
  const [usedTickets, setUsedTickets] = useState([]);
  const [payCount, setPayCount] = useState(0);
  const [adminError, setAdminError] = useState("");

  useEffect(() => {
    const saved = localStorage.getItem("mmr_used_tickets");
    const savedPay = localStorage.getItem("mmr_pay_count");
    if (saved) setUsedTickets(JSON.parse(saved));
    if (savedPay) setPayCount(parseInt(savedPay));
  }, []);

  const saveUsed = (tickets) => {
    setUsedTickets(tickets);
    localStorage.setItem("mmr_used_tickets", JSON.stringify(tickets));
  };

  const handleTicketCheck = () => {
    const val = ticketInput.trim().toUpperCase();
    if (!TICKETS.includes(val)) {
      setTicketStatus("invalid");
    } else if (usedTickets.includes(val)) {
      setTicketStatus("used");
    } else {
      setTicketStatus("valid");
      const newUsed = [...usedTickets, val];
      saveUsed(newUsed);
    }
  };

  const handlePayConfirm = () => {
    const newCount = payCount + 1;
    setPayCount(newCount);
    localStorage.setItem("mmr_pay_count", newCount.toString());
    setView("pay_done");
  };

  const handleAdminLogin = () => {
    if (adminPass === ADMIN_PASSWORD) {
      setAdminAuth(true);
      setAdminError("");
    } else {
      setAdminError("비밀번호가 맞지 않아요");
    }
  };

  const resetAll = () => {
    if (window.confirm("모든 티켓 데이터를 초기화할까요?")) {
      saveUsed([]);
      setPayCount(0);
      localStorage.removeItem("mmr_pay_count");
    }
  };

  // ── STYLES ──────────────────────────────────────────────
  const bg = {
    minHeight: "100vh",
    backgroundColor: "#03030c",
    backgroundImage: SPACE_LAYERS,
    backgroundSize: "auto",
    backgroundPosition: "top center",
    backgroundRepeat: "no-repeat",
    color: "#fff",
    fontFamily: "'Segoe UI', sans-serif",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    padding: "0 0 40px",
    position: "relative",
    overflowX: "hidden",
  };

  const glowPink = "0 0 18px #ff3d8b88, 0 0 40px #ff3d8b44";
  const glowBlue = "0 0 18px #4dc8ff88, 0 0 40px #4dc8ff44";

  const backBtn = {
    background: "transparent",
    border: "1px solid #ffffff33",
    color: "#aaa",
    padding: "8px 18px",
    borderRadius: "20px",
    cursor: "pointer",
    marginBottom: "24px",
    fontSize: "13px",
  };

  const primaryBtn = (color = "#ff3d8b") => ({
    background: `linear-gradient(135deg, ${color}, ${color}aa)`,
    border: "none",
    color: "#fff",
    padding: "16px 32px",
    borderRadius: "12px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "700",
    width: "100%",
    boxShadow: `0 0 20px ${color}66`,
    letterSpacing: "0",
  });

  const ghostPinkBtn = {
    ...primaryBtn("#ff4fb0"),
    background: "linear-gradient(135deg, #ff79c8 0%, #ff4dae 45%, #f2369d 100%)",
    border: "1px solid rgba(255, 178, 225, 0.5)",
    boxShadow: "0 0 9px rgba(255, 79, 176, 0.48), 0 0 16px rgba(242, 54, 157, 0.22), inset 0 0 7px rgba(255,255,255,0.12)",
  };

  const ghostBlueBtn = {
    ...primaryBtn("#6f63ff"),
    background: "linear-gradient(135deg, #7b5cff 0%, #38d7ff 58%, #8b4dff 100%)",
    border: "1px solid rgba(190, 180, 255, 0.48)",
    boxShadow: "0 0 10px rgba(123, 92, 255, 0.58), 0 0 18px rgba(56, 215, 255, 0.28), inset 0 0 8px rgba(255,255,255,0.13)",
  };

  const card = {
    background: "rgba(255,255,255,0.04)",
    border: "1px solid rgba(255,255,255,0.1)",
    borderRadius: "16px",
    padding: "24px",
    width: "100%",
    maxWidth: "360px",
    marginTop: "16px",
    boxSizing: "border-box",
  };

  const input = {
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.2)",
    borderRadius: "10px",
    color: "#fff",
    padding: "14px 16px",
    width: "100%",
    fontSize: "18px",
    letterSpacing: "3px",
    textAlign: "center",
    textTransform: "uppercase",
    outline: "none",
    boxSizing: "border-box",
  };

  const titleStyle = {
    fontSize: "16px",
    color: "#ff3d8b",
    letterSpacing: "3px",
    textTransform: "uppercase",
    marginBottom: "4px",
    textShadow: glowPink,
  };

  const ticketPromptHeading = {
    color: "rgb(255,255,255)",
    fontSize: "22px",
    fontWeight: "700",
    lineHeight: "1.25",
  };

  const pageShell = {
    width: "100%",
    maxWidth: "392px",
    padding: "32px 16px 0",
    boxSizing: "border-box",
    margin: "0 auto",
    textAlign: "center",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
  };

  const posterTypeWrap = {
    width: "100%",
    maxWidth: "360px",
    height: "176px",
    overflow: "visible",
    margin: "0 auto 18px",
    position: "relative",
    background: "transparent",
    display: "flex",
    justifyContent: "center",
    alignItems: "flex-start",
  };

  const posterTypeImg = {
    width: "360px",
    maxWidth: "100%",
    display: "block",
    margin: "4px auto 0",
    position: "relative",
    zIndex: 1,
    filter: "drop-shadow(0 0 12px #ff3d8b66) drop-shadow(0 0 16px #4dc8ff44)",
  };

  const taglineStyle = {
    textAlign: "center",
    display: "inline-block",
    fontSize: "14px",
    fontWeight: "700",
    lineHeight: "1.4",
    color: "#d8d8de",
    marginBottom: "4px",
    transform: "skewX(-9deg)",
    transformOrigin: "center",
    letterSpacing: "0",
    background: "linear-gradient(90deg, #e6e6ec 0%, #cfcfd8 48%, #8f8f9d 100%)",
    WebkitBackgroundClip: "text",
    backgroundClip: "text",
    WebkitTextFillColor: "transparent",
  };

  // ── VIEWS ──────────────────────────────────────────────

  // MAIN
  if (view === "main") return (
    <div style={bg}>
      <div style={pageShell}>
        <div style={{ width: "100%", textAlign: "center", marginBottom: "20px" }}>
          <div style={posterTypeWrap}>
            <img src={TYPO_IMG} alt="MOROCK MOROCK Live in Hongdae" style={posterTypeImg} />
          </div>
          <div style={{ fontSize: "13px", color: "#ffffff88" }}>Live in Hongdae · 2026.07.04 SAT 18:00</div>
          <div style={{ fontSize: "12px", color: "#ffffff55", marginTop: "4px" }}>홍대 우주정거장 · 마포구 와우산로 29길 16 지하 1층</div>
        </div>

        <div style={{ ...card, display: "flex", flexDirection: "column", gap: "12px", marginTop: 0 }}>
          <div style={taglineStyle}>
            오늘, 음악으로 우주를 채우다
          </div>
          <button style={ghostBlueBtn} onClick={() => { setView("ticket"); setTicketStatus(null); setTicketInput(""); }}>
            티켓을 구매했어요
          </button>
          <button style={ghostPinkBtn} onClick={() => setView("payment")}>
            지금 구매할게요
          </button>
        </div>
      </div>

      <div
        onClick={() => setView("admin")}
        style={{ marginTop: "16px", textAlign: "center", color: "#ffffff22", fontSize: "11px", cursor: "pointer" }}
      >
        ···
      </div>
    </div>
  );

  // TICKET CHECK
  if (view === "ticket") return (
    <div style={bg}>
      <div style={pageShell}>
        <button style={backBtn} onClick={() => setView("main")}>← 뒤로</button>
        <div style={{ textAlign: "center" }}>
          <div style={titleStyle}>티켓 확인</div>
          <h2 style={{ ...ticketPromptHeading, margin: "8px 0 4px" }}>구매하신 티켓 번호를</h2>
          <h2 style={{ ...ticketPromptHeading, margin: "0 0 24px" }}>입력해 주세요</h2>
        </div>

        <div style={card}>
          <input
            style={input}
            placeholder="NOVA"
            value={ticketInput}
            onChange={e => { setTicketInput(e.target.value); setTicketStatus(null); }}
            onKeyDown={e => e.key === "Enter" && handleTicketCheck()}
          />
          <div style={{ height: "12px" }} />
          <button style={ghostPinkBtn} onClick={handleTicketCheck}>
            티켓 확인하기
          </button>

          {ticketStatus === "valid" && (
            <div style={{ marginTop: "20px", textAlign: "center", padding: "20px", background: "rgba(77,200,255,0.1)", borderRadius: "12px", border: "1px solid #4dc8ff55" }}>
              <div style={{ color: "#4dc8ff", fontWeight: "700", fontSize: "18px", textShadow: glowBlue }}>티켓 확인 완료!</div>
              <div style={{ color: "#ffffffaa", fontSize: "14px", marginTop: "8px" }}>입장을 환영합니다</div>
              <div style={{ color: "#ffffff55", fontSize: "12px", marginTop: "4px" }}>공연 스태프에게 이 화면을 보여주세요</div>
            </div>
          )}

          {ticketStatus === "used" && (
            <div style={{ marginTop: "20px", textAlign: "center", padding: "20px", background: "rgba(255,61,139,0.1)", borderRadius: "12px", border: "1px solid #ff3d8b55" }}>
              <div style={{ color: "#ff3d8b", fontWeight: "700", fontSize: "16px" }}>이미 사용된 티켓이에요</div>
              <div style={{ color: "#ffffffaa", fontSize: "13px", marginTop: "6px" }}>스태프에게 문의해 주세요</div>
            </div>
          )}

          {ticketStatus === "invalid" && (
            <div style={{ marginTop: "20px", textAlign: "center", padding: "20px", background: "rgba(255,100,0,0.1)", borderRadius: "12px", border: "1px solid #ff6400aa" }}>
              <div style={{ color: "#ff9944", fontWeight: "700", fontSize: "16px" }}>유효하지 않은 티켓이에요</div>
              <div style={{ color: "#ffffffaa", fontSize: "13px", marginTop: "6px" }}>번호를 다시 확인해 주세요<br/>예시: NOVA</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );

  // PAYMENT
  if (view === "payment") return (
    <div style={bg}>
      <div style={pageShell}>
        <button style={backBtn} onClick={() => setView("main")}>← 뒤로</button>
        <div style={{ textAlign: "center" }}>
          <div style={{ ...titleStyle, fontSize: "16px" }}>현장 결제</div>
          <h2 style={{ margin: "8px 0 4px", fontSize: "22px" }}>입장권 구매</h2>
          <div style={{ fontSize: "32px", fontWeight: "800", color: "#fff", margin: "16px 0", textShadow: glowPink }}>3,000원</div>
        </div>

        <div style={card}>
          <div style={{ textAlign: "center", color: "#fffffff0", fontSize: "17px", lineHeight: "1.75", marginBottom: "22px", textShadow: "0 0 10px rgba(255,255,255,0.16)" }}>
            아래 버튼을 눌러 카카오페이로<br/>3,000원을 송금해 주세요<br/>
            <span style={{ fontSize: "15px", color: "#ffffffc8" }}>결제 후 스태프에게 완료 화면을 보여주세요</span>
          </div>
          <a
            href={KAKAO_LINK}
            target="_blank"
            rel="noreferrer"
            style={{
              ...primaryBtn("#f9e000"),
              background: "#f9e000",
              color: "#241000",
              textDecoration: "none",
              display: "block",
              textAlign: "center",
              boxSizing: "border-box",
              boxShadow: "0 0 20px #f9e00066",
            }}
          >
            카카오페이로 결제하기
          </a>
          <div style={{ marginTop: "12px" }}>
            <button style={{ ...primaryBtn("#ffffff22"), background: "rgba(255,255,255,0.08)", boxShadow: "none", border: "1px solid rgba(255,255,255,0.2)" }} onClick={handlePayConfirm}>
              결제 완료했어요
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // PAY DONE
  if (view === "pay_done") return (
    <div style={bg}>
      <div style={pageShell}>
        <button style={backBtn} onClick={() => setView("main")}>← 처음으로</button>
        <div style={{ fontSize: "64px", margin: "40px 0 16px" }}>🎊</div>
        <div style={titleStyle}>결제 완료</div>
        <h2 style={{ margin: "8px 0 8px" }}>환영합니다!</h2>
        <p style={{ color: "#ffffff88", fontSize: "14px", lineHeight: "1.7" }}>
          오늘 밤, 함께 우주를 채워요 🚀<br/>
          <span style={{ fontSize: "12px", color: "#ffffff55" }}>이 화면을 스태프에게 보여주세요</span>
        </p>
        <div style={{ marginTop: "32px", padding: "20px", background: "rgba(77,200,255,0.08)", borderRadius: "12px", border: "1px solid #4dc8ff33" }}>
          <div style={{ color: "#4dc8ff", fontSize: "13px" }}>MOROCKMOROCK Live in Hongdae</div>
          <div style={{ color: "#ffffffaa", fontSize: "13px", marginTop: "4px" }}>2026.07.04 SAT 18:00</div>
          <div style={{ color: "#ffffff55", fontSize: "12px" }}>홍대 우주정거장</div>
        </div>
      </div>
    </div>
  );

  // ADMIN
  if (view === "admin") {
    if (!adminAuth) return (
      <div style={bg}>
        <div style={pageShell}>
          <button style={backBtn} onClick={() => setView("main")}>← 뒤로</button>
          <div style={{ textAlign: "center" }}>
            <div style={titleStyle}>🔒 어드민</div>
            <h2 style={{ margin: "8px 0 20px" }}>주최자 로그인</h2>
          </div>
          <div style={card}>
            <input
              type="password"
              style={{ ...input, letterSpacing: "4px" }}
              placeholder="비밀번호"
              value={adminPass}
              onChange={e => setAdminPass(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleAdminLogin()}
            />
            {adminError && <div style={{ color: "#ff3d8b", fontSize: "13px", textAlign: "center", marginTop: "8px" }}>{adminError}</div>}
            <div style={{ height: "12px" }} />
            <button style={primaryBtn()} onClick={handleAdminLogin}>로그인</button>
          </div>
        </div>
      </div>
    );

    return (
      <div style={bg}>
        <div style={pageShell}>
          <button style={backBtn} onClick={() => { setView("main"); setAdminAuth(false); setAdminPass(""); }}>← 나가기</button>
          <div style={titleStyle}>🎛 어드민 대시보드</div>
          <h2 style={{ margin: "8px 0 20px" }}>공연 정산 현황</h2>

          {/* 요약 */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px", marginBottom: "16px" }}>
            <div style={{ ...card, margin: 0, textAlign: "center" }}>
              <div style={{ fontSize: "28px", fontWeight: "800", color: "#ff3d8b", textShadow: glowPink }}>{usedTickets.length}</div>
              <div style={{ fontSize: "12px", color: "#ffffff77", marginTop: "4px" }}>사용된 티켓</div>
            </div>
            <div style={{ ...card, margin: 0, textAlign: "center" }}>
              <div style={{ fontSize: "28px", fontWeight: "800", color: "#4dc8ff", textShadow: glowBlue }}>{payCount}</div>
              <div style={{ fontSize: "12px", color: "#ffffff77", marginTop: "4px" }}>현장 결제</div>
            </div>
          </div>

          <div style={{ ...card, textAlign: "center", marginBottom: "16px" }}>
            <div style={{ fontSize: "12px", color: "#ffffff77" }}>현장 결제 예상 수익</div>
            <div style={{ fontSize: "24px", fontWeight: "800", color: "#f9e000", marginTop: "4px" }}>
              {(payCount * 3000).toLocaleString()}원
            </div>
            <div style={{ fontSize: "11px", color: "#ffffff44", marginTop: "2px" }}>
              티켓 후불 정산 ({usedTickets.length}매) 별도
            </div>
          </div>

          {/* 사용된 티켓 목록 */}
          {usedTickets.length > 0 && (
            <div style={card}>
              <div style={{ fontSize: "13px", color: "#ffffff88", marginBottom: "12px" }}>✅ 사용된 티켓 ({usedTickets.length}매)</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
                {usedTickets.map((t, i) => (
                  <div key={i} style={{
                    background: "rgba(77,200,255,0.1)",
                    border: "1px solid #4dc8ff44",
                    borderRadius: "6px",
                    padding: "4px 10px",
                    fontSize: "11px",
                    color: "#4dc8ffcc",
                    letterSpacing: "1px",
                  }}>{t}</div>
                ))}
              </div>
            </div>
          )}

          {/* 전체 티켓 현황 */}
          <div style={{ ...card, marginTop: "12px" }}>
            <div style={{ fontSize: "13px", color: "#ffffff88", marginBottom: "12px" }}>🎫 전체 티켓 현황</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
              {TICKETS.map((t, i) => {
                const used = usedTickets.includes(t);
                return (
                  <div key={i} style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "6px 10px",
                    borderRadius: "6px",
                    background: used ? "rgba(77,200,255,0.06)" : "rgba(255,255,255,0.03)",
                    fontSize: "12px",
                  }}>
                    <span style={{ color: used ? "#4dc8ffcc" : "#ffffff66", letterSpacing: "1px" }}>{t}</span>
                    <span style={{ color: used ? "#4dc8ff" : "#ffffff33", fontSize: "11px" }}>
                      {used ? "✅ 사용됨" : "○ 미사용"}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>

          <button
            style={{ ...primaryBtn("#ff3d8b33"), marginTop: "16px", background: "rgba(255,61,139,0.1)", boxShadow: "none", border: "1px solid #ff3d8b44", color: "#ff3d8b88" }}
            onClick={resetAll}
          >
            데이터 초기화
          </button>
        </div>
      </div>
    );
  }

  return null;
}
